type ActionState = 
  | { type: 'VALIDE'; payload: { action: string; val: number } }
  | { type: 'ERREUR'; message: string };

function analyserCommande(state: ActionState): string {
  // Type Narrowing automatique via Discriminated Union
  switch (state.type) {
    case 'VALIDE': {
      const statut = state.payload.val > 0 ? 'Actif' : 'Inactif';
      if (state.payload.val <= 0) return 'Valeur négative ou nulle';
      if (state.payload.val <= 10) return `Commande '${state.payload.action}' (${statut})`;
      return 'Commande standard';
    }
    case 'ERREUR':
      return `Erreur : ${state.message}`;
  }
}

